import { forwardRef } from 'react';
import type { InputHTMLAttributes, SelectHTMLAttributes, TextareaHTMLAttributes } from 'react';

type FieldInputProps = {
  as?: 'input' | undefined;
} & InputHTMLAttributes<HTMLInputElement>;

type FieldTextareaProps = {
  as: 'textarea';
} & TextareaHTMLAttributes<HTMLTextAreaElement>;

type FieldSelectProps = {
  as: 'select';
} & SelectHTMLAttributes<HTMLSelectElement>;

type FieldCheckboxProps = {
  as: 'checkbox';
} & Omit<InputHTMLAttributes<HTMLInputElement>, 'type'>;

export type FieldProps = FieldInputProps | FieldTextareaProps | FieldSelectProps | FieldCheckboxProps;

export const Field = forwardRef<
  HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement,
  FieldProps
>(function Field(props, ref) {
  if (props.as === 'textarea') {
    const { as, ...t } = props;
    void as;
    return <textarea ref={ref as React.ForwardedRef<HTMLTextAreaElement>} {...t} />;
  }

  if (props.as === 'select') {
    const { as, children, ...s } = props;
    void as;
    return (
      <select ref={ref as React.ForwardedRef<HTMLSelectElement>} {...s}>
        {children}
      </select>
    );
  }

  if (props.as === 'checkbox') {
    const { as, ...c } = props;
    void as;
    return <input ref={ref as React.ForwardedRef<HTMLInputElement>} type="checkbox" {...c} />;
  }

  const { as, ...i } = props as FieldInputProps;
  void as;
  return <input ref={ref as React.ForwardedRef<HTMLInputElement>} {...i} />;
});

Field.displayName = 'Field';
